  1→import { existsSync, mkdirSync, statSync } from "node:fs";
  2→import { join, dirname, resolve } from "node:path";
  3→import { homedir } from "node:os";
  4→
  5→const BRAIN_DIR = join(homedir(), ".brain");
  6→const CONFIG_PATH = join(BRAIN_DIR, "config.json");
  7→
  8→/** Resolved config for a single repo — shape consumed by BrainHttpClient and all commands. */
  9→export type BrainConfig = {
 10→  server_url: string;
 11→  workspace: string;
 12→  client_id: string;
 13→  access_token: string;
 14→  refresh_token: string;
 15→  token_expires_at: number;
 16→};
 17→
 18→/** Per-repo auth entry in ~/.brain/config.json */
 19→export type RepoConfig = {
 20→  workspace: string;
 21→  client_id: string;
 22→  access_token: string;
 23→  refresh_token: string;
 24→  token_expires_at: number;
 25→};
 26→
 27→/** Root shape of ~/.brain/config.json */
 28→export type BrainGlobalConfig = {
 29→  server_url: string;
 30→  repos: Record<string, RepoConfig>;
 31→};
 32→
 33→// ---------------------------------------------------------------------------
 34→// Git root
 35→// ---------------------------------------------------------------------------
 36→
 37→/**
 38→ * Find the main repository root from any path, including worktrees.
 39→ *
 40→ * In a regular repo, `.git` is a directory → that dir is the root.
 41→ * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 42→ * We follow the pointer back to the main repo so all worktrees share one config key.
 43→ */
 44→export function findGitRoot(from: string): string | undefined {
 45→  let dir = from;
 46→  while (dir !== "/") {
 47→    const gitPath = join(dir, ".git");
 48→    if (existsSync(gitPath)) {
 49→      if (statSync(gitPath).isFile()) {
 50→        return resolveWorktreeMainRoot(gitPath) ?? dir;
 51→      }
 52→      return dir;
 53→    }
 54→    dir = dirname(dir);
 55→  }
 56→  return undefined;
 57→}
 58→
 59→/** Read a worktree .git file and resolve to the main repo root. */
 60→function resolveWorktreeMainRoot(gitFile: string): string | undefined {
 61→  try {
 62→    const content = Bun.file(gitFile).textSync().trim();
 63→    const match = content.match(/^gitdir:\s*(.+)$/);
 64→    if (!match) return undefined;
 65→
 66→    const gitdir = resolve(dirname(gitFile), match[1]);
 67→    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
 68→    return dirname(dotGit);
 69→  } catch {
 70→    return undefined;
 71→  }
 72→}
 73→
 74→// ---------------------------------------------------------------------------
 75→// Global config (~/.brain/config.json)
 76→// ---------------------------------------------------------------------------
 77→
 78→function ensureBrainDir(): void {
 79→  if (!existsSync(BRAIN_DIR)) mkdirSync(BRAIN_DIR, { recursive: true });
 80→}
 81→
 82→export async function loadGlobalConfig(): Promise<BrainGlobalConfig | undefined> {
 83→  const file = Bun.file(CONFIG_PATH);
 84→  if (!(await file.exists())) return undefined;
 85→  try {
 86→    return await file.json() as BrainGlobalConfig;
 87→  } catch {
 88→    return undefined;
 89→  }
 90→}
 91→
 92→export async function saveGlobalConfig(config: BrainGlobalConfig): Promise<void> {
 93→  ensureBrainDir();
 94→  await Bun.write(CONFIG_PATH, JSON.stringify(config, null, 2) + "\n");
 95→}
 96→
 97→/** Upsert a repo entry in the global config. Creates the file if needed. */
 98→export async function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): Promise<void> {
 99→  const global = (await loadGlobalConfig()) ?? { server_url: serverUrl, repos: {} };
100→  global.server_url = serverUrl;
101→  global.repos[gitRoot] = repo;
102→  await saveGlobalConfig(global);
103→}
104→
105→// ---------------------------------------------------------------------------
106→// Resolved config (what consumers use)
107→// ---------------------------------------------------------------------------
108→
109→/** Resolve BrainConfig for the current repo from ~/.brain/config.json.
110→ *  The server URL can be overridden via the BRAIN_SERVER_URL env var. */
111→export async function loadConfig(): Promise<BrainConfig | undefined> {
112→  const gitRoot = findGitRoot(process.cwd());
113→  const global = await loadGlobalConfig();
114→  if (global && gitRoot && global.repos[gitRoot]) {
115→    const repo = global.repos[gitRoot];
116→    const serverUrl = process.env.BRAIN_SERVER_URL ?? global.server_url;
117→    return {
118→      server_url: serverUrl,
119→      workspace: repo.workspace,
120→      client_id: repo.client_id,
121→      access_token: repo.access_token,
122→      refresh_token: repo.refresh_token,
123→      token_expires_at: repo.token_expires_at,
124→    };
125→  }
126→  return undefined;
127→}
128→
129→export async function requireConfig(): Promise<BrainConfig> {
130→  const config = await loadConfig();
131→  if (!config) {
132→    console.error("Brain not configured. Run: brain init");
133→    process.exit(1);
134→  }
135→  return config;
136→}
